function replaceFayinrenName(name) {
  var originalName = String(name || "");
  var mapData = getFayinrenMapCached();

  for (var i = 0; i < mapData.length; i++) {
    if ((mapData[i][0] || "") === originalName) {
      return mapData[i][1] || originalName;
    }
  }
  return originalName;
}

function reverseReplaceFayinrenName(displayName) {
  var originalName = String(displayName || "");
  var mapData = getFayinrenMapCached();

  for (var i = 0; i < mapData.length; i++) {
    if ((mapData[i][1] || "") === originalName) {
      return mapData[i][0] || originalName;
    }
  }
  return originalName;
}

