    function pickBookFromText(raw) {
      raw = String(raw || "");
      if (!raw) return "";

      try {
        raw = raw.replace(/\\u([0-9a-fA-F]{4})/g, function (_, h) {
          return String.fromCharCode(parseInt(h, 16));
        });
      } catch (e) {}

      var patterns = [
        /书\s*[=:：]\s*([^|，,；;\n\r]+)/,
        /书名\s*[=:：]\s*([^|，,；;\n\r]+)/,
        /bookName\s*["']?\s*[:=]\s*["']([^"']+)["']/i,
        /bookTitle\s*["']?\s*[:=]\s*["']([^"']+)["']/i,
        /"book"\s*:\s*"([^"]+)"/i
      ];

      for (var i = 0; i < patterns.length; i++) {
        var m = raw.match(patterns[i]);
        if (m && m[1]) {
          var name = normalizeBookName(m[1]);
          if (isValidBookName(name)) return name;
        }
      }

      return "";
    }

    function pickBookFromObject(obj) {
      var best = "";

      function walk(o, depth) {
        if (best || depth > 5 || o === null || typeof o === "undefined") return;

        if (typeof o === "string") {
          best = pickBookFromText(o);
          return;
        }

        if (typeof o !== "object") return;

        var keys = ["bookName", "bookTitle", "book", "name", "book_name", "book_title"];
        for (var i = 0; i < keys.length; i++) {
          var k = keys[i];
          if (typeof o[k] === "string") {
            var n = normalizeBookName(o[k]);
            if (isValidBookName(n)) {
              best = n;
              return;
            }
          }
        }

        var preferred = ["data", "current", "currentBook", "bookInfo", "result", "content"];
        for (var p = 0; p < preferred.length; p++) {
          if (o.hasOwnProperty && o.hasOwnProperty(preferred[p])) {
            walk(o[preferred[p]], depth + 1);
            if (best) return;
          }
        }

        if (Object.prototype.toString.call(o) === "[object Array]") {
          for (var a = 0; a < o.length && a < 5; a++) {
            walk(o[a], depth + 1);
            if (best) return;
          }
        } else {
          for (var key in o) {
            if (!o.hasOwnProperty || o.hasOwnProperty(key)) {
              walk(o[key], depth + 1);
              if (best) return;
            }
          }
        }
      }

      walk(obj, 0);
      return best;
    }

    function readBookNameFromHttpCurrentChapter() {
      function getReaderWebBaseUrl() {
        try {
          var cfg = readText("reader_web_base_url.txt", "");
          cfg = String(cfg || "").trim();
          if (cfg) return cfg.replace(/\/+$/, "");
        } catch (e) {}
        return "http://192.168.5.6:18326";
      }

      var baseUrl = getReaderWebBaseUrl();
      var paths = ["/tts/current-chapter", "/current-chapter", "/tts/current", "/current", "/book/current"];

      function tryGetRaw(url) {
        var conn = null;
        var reader = null;

        try {
          var URL = java.net.URL;
          var BufferedReader = java.io.BufferedReader;
          var InputStreamReader = java.io.InputStreamReader;
          var StringBuilder = java.lang.StringBuilder;

          conn = new URL(url).openConnection();
          conn.setConnectTimeout(1200);
          conn.setReadTimeout(1200);

          try { conn.setRequestMethod("GET"); } catch (eMethod) {}

          var code = 200;
          try {
            if (conn.getResponseCode) code = conn.getResponseCode();
          } catch (eCode) {}

          if (code < 200 || code >= 300) return "";

          reader = new BufferedReader(new InputStreamReader(conn.getInputStream(), "UTF-8"));
          var sb = new StringBuilder();
          var line;

          while ((line = reader.readLine()) !== null) {
            sb.append(line).append("\n");
          }

          return String(sb.toString() || "");
        } catch (e) {
          console.log("【自动跟随书名】Web读取失败，已忽略：" + url + " | " + e.toString());
          return "";
        } finally {
          try { if (reader) reader.close(); } catch (eClose) {}
          try { if (conn && conn.disconnect) conn.disconnect(); } catch (eDis) {}
        }
      }

      for (var i = 0; i < paths.length; i++) {
        var url = baseUrl + paths[i];
        var raw = tryGetRaw(url);
        if (!raw) continue;

        var bookName = "";
        try {
          bookName = pickBookFromObject(JSON.parse(raw));
        } catch (eJson) {
          bookName = pickBookFromText(raw);
        }

        if (isValidBookName(bookName)) {
          persistBookNameForRoleManager(bookName, { sourceUrl: url });
          return bookName;
        }
      }

      return "";
    }

    function isEmptyRoleData(raw) {
