    function switchRoleManagerToExternalBook(newBookName, oldBookName, forceInherit) {
      newBookName = normalizeBookName(newBookName);
      oldBookName = normalizeBookName(oldBookName || currentUiBookName || getSelectedBookFromSpinnerSafe() || autoBookFollowLastBook || "");
      if (!isValidBookName(newBookName)) return;
      if (autoBookFollowBusy) return;

      autoBookFollowBusy = true;

      try {
        var currentVisibleData = getCurrentVisibleRoleData();

        if (isEmptyRoleData(currentVisibleData) && isValidBookName(oldBookName)) {
          try {
            var oldBookData = readText("shuming." + oldBookName + ".json", "");
            if (!isEmptyRoleData(oldBookData)) currentVisibleData = oldBookData;
          } catch (eOld) {}
        }

        // 自动切书前，先把当前 UI 角色保存到旧书文件
        if (isValidBookName(oldBookName) && oldBookName !== newBookName && !isEmptyRoleData(currentVisibleData)) {
          writeText("shuming." + oldBookName + ".json", currentVisibleData);
          writeText("characterRecords.json", currentVisibleData);
          rememberNonEmptyRoleData(currentVisibleData);
        }

        var newBookFile = "shuming." + newBookName + ".json";
        var existedNewBookData = readText(newBookFile, "");

        persistBookNameForRoleManager(newBookName, null);

        var shouldInherit = (forceInherit || isEmptyRoleData(existedNewBookData)) && !isEmptyRoleData(currentVisibleData);
        if (shouldInherit) {
          writeText(newBookFile, currentVisibleData);
          existedNewBookData = currentVisibleData;
          console.log("【自动跟随书名】新书无角色数据，已继承当前角色列表：" + newBookName);
        }

        var bookData = readText(newBookFile, "[]");
        if (!bookData || String(bookData).trim() === "") bookData = "[]";

        var parsed = JSON.parse(bookData);
        characterRecords = Array.isArray(parsed) ? parsed : [];

        for (var i = 0; i < characterRecords.length; i++) {
          characterRecords[i].voice = replaceFayinrenName(characterRecords[i].voice || "");
        }

        var normalizedData = JSON.stringify(characterRecords, null, 2);
        rememberNonEmptyRoleData(normalizedData);
        writeText("characterRecords.json", normalizedData);
        createGengxinFile();
        refreshCharacterList();

        currentUiBookName = newBookName;
        autoBookFollowLastBook = newBookName;
        initBookSpinner(false);
      } catch (e) {
        console.error("自动跟随切书失败：" + e.toString());
      } finally {
        autoBookFollowBusy = false;
      }
    }




    function autoFollowCurrentBookOnce(showToast) {
      if (!AUTO_BOOK_FOLLOW_ENABLE) return;
      if (autoBookFollowBusy || autoBookFollowHttpBusy) return;

      // 先记录当前 UI 选择的书名。之后 HTTP 可能会写 cunfang.txt，不能再用 getCurrentBookName 当旧书。
      var uiBookBeforeFollow = normalizeBookName(currentUiBookName || getSelectedBookFromSpinnerSafe() || autoBookFollowLastBook || "");

      autoBookFollowHttpBusy = true;

      try {
        var task = new java.lang.Runnable({
          run: function () {
            var currentOpenedBook = "";
            try {
              currentOpenedBook = readBookNameFromHttpCurrentChapter();
            } catch (eHttp) {
              currentOpenedBook = "";
            }

            try {
              if (!isValidBookName(currentOpenedBook)) {
                currentOpenedBook = readBookNameFromLocalFollowCache();
              }

              if (isValidBookName(currentOpenedBook)) {
                var compareBook = normalizeBookName(uiBookBeforeFollow || currentUiBookName || autoBookFollowLastBook || getSelectedBookFromSpinnerSafe());

                // 关键修正：对比 UI 当前选中的书，而不是已经被 HTTP 写入的 cunfang.txt。
                if (!compareBook || currentOpenedBook !== compareBook) {
                  var bookToSwitch = currentOpenedBook;
                  var oldBookForInherit = compareBook;
                  var mainHandler = autoBookFollowHandler || new android.os.Handler(android.os.Looper.getMainLooper());
                  mainHandler.post(new java.lang.Runnable({
                    run: function () {
                      switchRoleManagerToExternalBook(bookToSwitch, oldBookForInherit, false);
                      if (showToast) toast("已跟随当前书：" + bookToSwitch);
                    }
                  }));
                } else if (showToast) {
                  var handler = autoBookFollowHandler || new android.os.Handler(android.os.Looper.getMainLooper());
                  handler.post(new java.lang.Runnable({
                    run: function () {
                      // 即使书名相同，也刷新一次列表，避免切书后必须手动刷新。
                      try {
                        loadCharactersFromCurrentFile();
                        refreshCharacterList();
                        initBookSpinner(false);
                      } catch (refreshErr) {}
                      toast("当前已是：" + currentOpenedBook + "，已刷新角色列表");
                    }
                  }));
                }
              } else if (showToast) {
                var h = autoBookFollowHandler || new android.os.Handler(android.os.Looper.getMainLooper());
                h.post(new java.lang.Runnable({
                  run: function () { toast("未读取到当前书名"); }
                }));
              }
            } catch (e) {
              if (showToast) {
                try {
                  var eh = autoBookFollowHandler || new android.os.Handler(android.os.Looper.getMainLooper());
                  eh.post(new java.lang.Runnable({
                    run: function () { toast("跟随当前书失败：" + e.toString()); }
                  }));
                } catch (ePost) {}
              }
            } finally {
              autoBookFollowHttpBusy = false;
            }
          }
        });
        new java.lang.Thread(task).start();
      } catch (eStart) {
        autoBookFollowHttpBusy = false;
      }
    }


    function startAutoBookFollowTimer() {
      if (autoBookFollowStarted) return;
      autoBookFollowStarted = true;

      try {
        // 不用 getCurrentBookName 初始化，因为 HTTP/缓存可能已经被外部切书改成新书；
        // 这里以 UI 下拉框当前显示为准，才能判断“是否需要切书并继承角色”。
        autoBookFollowLastBook = normalizeBookName(getSelectedBookFromSpinnerSafe() || "");
        autoBookFollowHandler = new android.os.Handler(android.os.Looper.getMainLooper());
        autoBookFollowRunnable = new java.lang.Runnable({
          run: function () {
            try {
              autoFollowCurrentBookOnce(false);
            } catch (e) {}
            try {
              autoBookFollowHandler.postDelayed(autoBookFollowRunnable, AUTO_BOOK_FOLLOW_INTERVAL_MS);
            } catch (ePost) {}
          }
        });
        autoBookFollowHandler.postDelayed(autoBookFollowRunnable, AUTO_BOOK_FOLLOW_INTERVAL_MS);
      } catch (e) {}
    }


