    function safeGetName(character) {
      return character && character.name ? String(character.name) : "未知角色";
    }

    function formatVoiceTextForCharacterList(voiceText) {
      var raw = String(voiceText || "").trim();
      if (raw === "") return "";

      var bracketMatch = raw.match(/^【([^】]+)】(.*)$/);
      if (bracketMatch) {
        var inside = String(bracketMatch[1] || "").trim();
        var after = String(bracketMatch[2] || "").trim();
        if (inside.indexOf("/") !== -1 || inside.indexOf("旁白") !== -1 || inside.indexOf("音效") !== -1) {
          return "【" + inside + "】" + after;
        }
        raw = inside + after;
      }

      var prefixRules = [
        ["主角 男主", "主角 男主"],
        ["主角 女主", "主角 女主"],
        ["男青年", "男/男青年"],
        ["女青年", "女/女青年"],
        ["男中年", "男/男中年"],
        ["女中年", "女/女中年"],
        ["男老年", "男/男老年"],
        ["女老年", "女/女老年"],
        ["男童", "男/男童"],
        ["女童", "女/女童"],
        ["少年", "男/少年"],
        ["少女", "女/少女"],
        ["特殊男", "男/特殊"],
        ["特殊女", "女/特殊"],
        ["旁白", "旁白"]
      ];

      for (var i = 0; i < prefixRules.length; i++) {
        var prefix = prefixRules[i][0];
        var displayPrefix = prefixRules[i][1];
        if (raw.indexOf(prefix) === 0) {
          var tail = raw.substring(prefix.length);
          var numMatch = tail.match(/^(\d{1,3})(.*)$/);
          if (numMatch) {
            var num = numMatch[1];
            var rest = numMatch[2] || "";
            var tagNo = num.length >= 2 ? num.substring(0, 2) : ("0" + num);
            var remainNo = num.length > 2 ? num.substring(2) : "";
            return "【" + displayPrefix + tagNo + "】" + remainNo + rest;
          }
          return "【" + displayPrefix + "】" + tail;
        }
      }

      return raw;
    }

    function generateDisplayText(character) {
      if (!character) return "无效角色";

      var name = safeGetName(character);
      var displayText = name;

      if (character.age === "主角" || character.gender === "主角" || character.age === "男主" || character.age === "女主") {
        displayText += "👑";
      }

      if (character.usageCount === 50) {
        displayText = "【" + displayText + "】";
      }

      if (character.aliases && character.aliases !== name) {
        displayText += " (" + character.aliases + ")";
      }

      if (character.voice) {
        var voiceText = formatVoiceTextForCharacterList(character.voice);
        if (voiceText) displayText += "  " + voiceText;
      }

      if (displayText.length > 120) displayText = displayText.substring(0, 120) + "…";
      return displayText;
    }

