    function updateListViewHeight() {
      try {
        var count = characterRecords.length;
        var metrics = ctx.getResources().getDisplayMetrics();
        var screenHeight = metrics.heightPixels;

        // 角色列表加高版：
        // 少量角色按内容高度显示；角色多时最多占屏幕约 60%，列表内部自己上下滑动。
        var minHeight = Math.floor(150 * density + 0.5);
        var maxHeightByDp = Math.floor(560 * density + 0.5);
        var maxHeightByScreen = Math.floor(screenHeight * 0.60);
        var maxHeight = Math.min(maxHeightByDp, maxHeightByScreen);
        if (maxHeight < minHeight) maxHeight = minHeight;

        var rowHeight = Math.floor(54 * density + 0.5);
        var wantedHeight = rowHeight * Math.max(1, count);
        var finalHeight = Math.min(Math.max(wantedHeight, minHeight), maxHeight);

        var params = new android.widget.LinearLayout.LayoutParams(
          android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
          finalHeight
        );
        mergeListView.setLayoutParams(params);
        mergeListView.setVerticalScrollBarEnabled(wantedHeight > finalHeight);
        mergeListView.setFastScrollEnabled(count > 24);
        mergeListView.requestLayout();
        mergeListView.invalidate();
      } catch (e) {}
    }

