    // ====================== 密钥保存/恢复：全列表隐藏版 ======================
    function normalizeKeyMap(raw, out, sourceName) {
      out = out || {};
      sourceName = sourceName || "key";

      function putKey(name, value, keyCode) {
        name = String(name || "").trim();
        value = String(value || "").trim();
        if (!value) return;

        if (!name) name = keyCode || "key";
        var baseName = name;
        var n = 2;
        while (Object.prototype.hasOwnProperty.call(out, name) && String(out[name].value || "") !== value) {
          name = baseName + "_" + n;
          n++;
        }

        out[name] = {
          keyCode: keyCode || (out[name] && out[name].keyCode) || name,
          value: value
        };
      }

      if (raw === null || typeof raw === "undefined") return out;

      // Rhino 安全修复：
      // 只能处理字符串 / 纯 JS 数组 / 纯 JS Object。
      // ttsrv.tts.data 里某些字段可能是 JavaObject，遍历它会触发访问 java.lang.Class 并被沙箱拦截。
      if (typeof raw !== "string") {
        var tag = "";
        try {
          tag = Object.prototype.toString.call(raw);
        } catch (eTag) {
          return out;
        }

        if (tag !== "[object Object]" && tag !== "[object Array]") {
          return out;
        }
      }

      if (typeof raw === "string") {
        var str = String(raw).trim();
        if (!str) return out;

        try {
          raw = JSON.parse(str);
        } catch (eJson) {
          putKey(sourceName, str, sourceName);
          return out;
        }
      }

      var tag2 = "";
      try {
        tag2 = Object.prototype.toString.call(raw);
      } catch (eTag2) {
        return out;
      }

      if (tag2 === "[object Array]") {
        for (var i = 0; i < raw.length; i++) {
          var it = raw[i];
          if (!it) continue;

          if (typeof it === "string") {
            putKey(sourceName + "_" + (i + 1), it, sourceName + "_" + (i + 1));
          } else {
            var itTag = "";
            try { itTag = Object.prototype.toString.call(it); } catch (eItTag) { itTag = ""; }
            if (itTag === "[object Object]") {
              var name = it.name || it.title || it.keyName || it.alias || it.label || it.keyCode || ("key" + (i + 1));
              var value = it.value || it.key || it.secret || it.apiKey || it.token || "";
              putKey(name, value, it.keyCode || name);
            }
          }
        }
        return out;
      }

      if (tag2 === "[object Object]") {
        // 兼容 { keyMap: {...} } / { keys: [...] } 这种包裹结构。
        try {
          if (raw.keyMap) normalizeKeyMap(raw.keyMap, out, "keyMap");
          if (raw.keys) normalizeKeyMap(raw.keys, out, "keys");
          if (raw.keyList) normalizeKeyMap(raw.keyList, out, "keyList");
          if (raw.savedKeys) normalizeKeyMap(raw.savedKeys, out, "savedKeys");
        } catch (eWrap) {}

        for (var name in raw) {
          if (!Object.prototype.hasOwnProperty.call(raw, name)) continue;
          if (name === "keyMap" || name === "keys" || name === "keyList" || name === "savedKeys") continue;

          var v;
          try {
            v = raw[name];
          } catch (eRead) {
            continue;
          }

          if (typeof v === "string") {
            putKey(name, v, name);
          } else {
            var vTag = "";
            try { vTag = Object.prototype.toString.call(v); } catch (eVTag) { vTag = ""; }
            if (vTag === "[object Object]") {
              var value = v.value || v.key || v.secret || v.apiKey || v.token || "";
              var keyCode = v.keyCode || name;
              putKey(name, value, keyCode);
            }
          }
        }
      }

      return out;
    }


    function getKeyMapFromData() {
      if (typeof ttsrv.tts === "undefined") ttsrv.tts = {};
      if (typeof ttsrv.tts.data !== "object") ttsrv.tts.data = {};

      var out = {};

      // 旧版主要保存在 keyListJson；新版也继续兼容。
      // 注意：不要遍历 ttsrv.tts.data 全对象，Rhino 沙箱里可能会触发 java.lang.Class 禁止访问。
      try {
        normalizeKeyMap(String(ttsrv.tts.data.keyListJson || "{}"), out, "keyListJson");
      } catch (eKeyListJson) {}

      // 以下字段只在明确是字符串时解析；避免 JavaObject 触发沙箱崩溃。
      try {
        if (typeof ttsrv.tts.data.keyMap === "string") normalizeKeyMap(ttsrv.tts.data.keyMap, out, "keyMap");
      } catch (eKeyMap) {}
      try {
        if (typeof ttsrv.tts.data.keyList === "string") normalizeKeyMap(ttsrv.tts.data.keyList, out, "keyList");
      } catch (eKeyList) {}
      try {
        if (typeof ttsrv.tts.data.savedKeys === "string") normalizeKeyMap(ttsrv.tts.data.savedKeys, out, "savedKeys");
      } catch (eSavedKeys) {}
      try {
        if (typeof ttsrv.tts.data.keys === "string") normalizeKeyMap(ttsrv.tts.data.keys, out, "keys");
      } catch (eKeys) {}

      // 当前输入/本地密钥只作为兜底，不覆盖已保存列表。
      try {
        var dataKey = String(ttsrv.tts.data.key || "").trim();
        if (dataKey) normalizeKeyMap({ "当前data密钥": dataKey }, out, "currentDataKey");
      } catch (eDataKey) {}

      try {
        var localKey = readText("miyue.txt", "").trim();
        if (localKey) normalizeKeyMap({ "当前本地密钥": localKey }, out, "localKey");
      } catch (eLocalKey) {}

      return out;
    }


    function saveKeyMapToData(keyMap) {
      try {
        // 统一写回旧版字段，保证以后原版/精简版都能读到所有密钥。
        ttsrv.tts.data.keyListJson = JSON.stringify(keyMap || {});
        return true;
      } catch (e) {
        console.error("保存密钥列表到 data 失败：" + e.toString());
        toast("保存密钥列表失败");
        return false;
      }
    }

    function getSortedKeyNames(keyMap) {
      var names = [];
      for (var name in keyMap) {
        if (Object.prototype.hasOwnProperty.call(keyMap, name)) names.push(name);
      }
      names.sort();
      return names;
    }

    function getNextKeyCode(keyMap) {
      var maxNum = 0;
      for (var name in keyMap) {
        if (!Object.prototype.hasOwnProperty.call(keyMap, name)) continue;
        var code = keyMap[name] && keyMap[name].keyCode ? String(keyMap[name].keyCode) : "";
        var m = code.match(/^key(\d+)$/i);
        if (m) {
          var n = parseInt(m[1], 10) || 0;
          if (n > maxNum) maxNum = n;
        }
      }
      var next = maxNum + 1;
      return "key" + (next < 10 ? "0" + next : String(next));
    }

    function saveKeyToLocal(key) {
      key = String(key || "").trim();
      if (!key) return false;
      try { writeText("miyue.txt", key); } catch (e1) {}
      try { writeText("gengxin.txt", key); } catch (e2) {}
      try { writeText("miyue_backup.txt", key); } catch (e3) {}
      return true;
    }

