    function saveCurrentKeyFromInput(keyInput) {
      var dataKey = "";
      try { dataKey = keyInput.getText().toString().trim(); } catch (e) { dataKey = ""; }
      if (!dataKey) {
        toast("密钥为空，不能保存");
        return;
      }

      var keyMap = getKeyMapFromData();
      var names = getSortedKeyNames(keyMap);
      var options = names.slice();
      options.push("保存为新密钥");

      var builder = new android.app.AlertDialog.Builder(ctx);
      builder.setTitle("保存密钥（现有 " + names.length + " 个）");
      builder.setItems(options, new android.content.DialogInterface.OnClickListener({
        onClick: function (dialog, which) {
          if (which < names.length) {
            var oldName = names[which];
            keyMap[oldName] = {
              keyCode: keyMap[oldName] && keyMap[oldName].keyCode ? keyMap[oldName].keyCode : getNextKeyCode(keyMap),
              value: dataKey
            };
