    }

    // 修复：固定当前发音人按钮恢复为“先弹出发音人搜索/选择框，再批量绑定到已标记角色”。
    // 适合一次性把选中的发音人链到所有已标记角色/tag 标签。
    function doFixMarkedVoiceOperation(selectedVoice) {
      if (markedIndices.length === 0) {
        toast("请先标记至少一个角色");
        return;
      }

      selectedVoice = String(selectedVoice || "").trim();
      if (!selectedVoice || selectedVoice === "follow_target") {
        toast("请选择有效发音人");
        return;
      }

      backupOriginalData();

      var fixedCount = 0;
      for (var i = 0; i < markedIndices.length; i++) {
        var idx = markedIndices[i];
        var ch = characterRecords[idx];
        if (ch) {
          ch.voice = selectedVoice;
          ch.usageCount = 100;
          fixedCount++;
        }
      }

      saveCharacterData();
      refreshCharacterList();
      toast("已把发音人「" + selectedVoice + "」固定到 " + fixedCount + " 个角色");
    }

    function getPreviousVoiceForMarkedRoles() {
      try {
        var idx = -1;

        if (selectedIndex >= 0 && markedIndices.indexOf(selectedIndex) !== -1) {
          idx = selectedIndex;
        } else if (markedIndices.length > 0) {
          idx = markedIndices[0];
        }

        if (idx >= 0 && idx < characterRecords.length) {
          var ch = characterRecords[idx];
          return String((ch && ch.voice) || "").trim();
        }
      } catch (e) {}
      return "";
    }

    function doFixVoiceOperation(selectedVoice) {
      if (selectedIndex < 0 || markedIndices.indexOf(selectedIndex) === -1) {
        toast("请标记并选中一个角色");
