    function doMergeOperation(newVoiceName) {
      if (markedIndices.length === 0 || selectedIndex < 0 || markedIndices.indexOf(selectedIndex) === -1) {
        toast("请标记并选中目标角色");
        return;
      }

      var targetRecord = characterRecords[selectedIndex];
      if (!targetRecord) return;

      backupOriginalData();

      if (markedIndices.length === 1) {
        if (newVoiceName && newVoiceName !== "follow_target") {
          targetRecord.voice = newVoiceName;
          targetRecord.usageCount = 100;
        }
        saveCharacterData();
        refreshCharacterList();
        toast("角色发音人更新成功");
        return;
      }

      var aliasMap = {};
      function addAlias(text) {
        text = String(text || "").trim();
        if (text) aliasMap[text] = true;
      }

      addAlias(targetRecord.name);
      if (targetRecord.aliases) {
        var targetAliases = String(targetRecord.aliases).split("|");
        for (var a = 0; a < targetAliases.length; a++) addAlias(targetAliases[a]);
      }

      var removeNames = {};
      for (var i = 0; i < markedIndices.length; i++) {
        var idx = markedIndices[i];
        if (idx === selectedIndex) continue;

        var ch = characterRecords[idx];
        if (!ch) continue;

        removeNames[normalizeString(ch.name)] = true;
        addAlias(ch.name);

        if (ch.aliases) {
          var aliases = String(ch.aliases).split("|");
          for (var j = 0; j < aliases.length; j++) addAlias(aliases[j]);
        }
      }

      if (newVoiceName && newVoiceName !== "follow_target") {
        targetRecord.voice = newVoiceName;
        targetRecord.usageCount = 100;
      }

      var mergedAliases = [];
      for (var key in aliasMap) {
        if (aliasMap.hasOwnProperty(key)) mergedAliases.push(key);
      }
      targetRecord.aliases = mergedAliases.join("|");

      var remaining = [];
      for (var r = 0; r < characterRecords.length; r++) {
        var item = characterRecords[r];
        if (!item) continue;
        if (r === selectedIndex) continue;
        if (removeNames[normalizeString(item.name)]) continue;
        remaining.push(item);
      }

      characterRecords = [targetRecord].concat(remaining);
      saveCharacterData();
      refreshCharacterList();
      toast("合并成功，目标角色已置顶");
    }

    function doReleaseOperation() {
      if (markedIndices.length === 0) {
        toast("请标记至少一个角色");
        return;
      }

      backupOriginalData();

      markedIndices.sort(function (a, b) { return b - a; });

      for (var m = 0; m < markedIndices.length; m++) {
        var index = markedIndices[m];
        var ch = characterRecords[index];
        if (!ch || !ch.aliases) continue;

        var name = safeGetName(ch);
        var aliases = String(ch.aliases).split("|");
        var newRecords = [];

        for (var i = 0; i < aliases.length; i++) {
          var alias = String(aliases[i] || "").trim();
          if (!alias || normalizeString(alias) === normalizeString(name)) continue;

          var exists = false;
          for (var j = 0; j < characterRecords.length; j++) {
            if (normalizeString(characterRecords[j].name) === normalizeString(alias)) {
              exists = true;
              break;
            }
          }

          if (!exists) {
            newRecords.push({
              name: alias,
              aliases: alias,
              voice: "",
              gender: "",
              age: "",
              usageCount: 0
            });
          }
        }

        ch.aliases = name;
        if (newRecords.length > 0) {
          var args = [index + 1, 0].concat(newRecords);
          Array.prototype.splice.apply(characterRecords, args);
        }
      }

      saveCharacterData();
      refreshCharacterList();
      toast("角色释放成功");
    }

    function doDeleteCharacterOperation() {
      if (markedIndices.length === 0) {
        toast("请标记至少一个角色");
        return;
      }

      new android.app.AlertDialog.Builder(ctx)
        .setTitle("确认删除")
        .setMessage("确定删除已标记的 " + markedIndices.length + " 个角色吗？")
        .setPositiveButton("删除", function () {
          backupOriginalData();
          var removeMap = {};
          for (var i = 0; i < markedIndices.length; i++) removeMap[markedIndices[i]] = true;

          var out = [];
          for (var j = 0; j < characterRecords.length; j++) {
            if (!removeMap[j]) out.push(characterRecords[j]);
          }

          characterRecords = out;
          saveCharacterData();
          refreshCharacterList();
          toast("已删除角色");
        })
        .setNegativeButton("取消", function (dialog) { dialog.dismiss(); })
        .show();
    }

    function doEditCharacterOperation(position) {
      if (position < 0 || position >= characterRecords.length) {
        toast("角色索引无效");
        return;
      }

      var target = characterRecords[position];
      var oldName = target.name || "";
      var oldAlias = target.aliases || oldName;
      var oldVoice = target.voice || "默认发音人";

      showInputDialog("修改角色名", function (newName) {
        newName = String(newName || "").trim();
