    function addCharacter() {
      showInputDialog("请输入角色名", function (name) {
        name = String(name || "").trim();
        if (!name) {
          toast("角色名不能为空");
          return;
        }

        showInputDialog("请输入角色别名（为空则使用角色名）", function (alias) {
          alias = String(alias || "").trim() || name;

          var tagOptions = [];
          for (var k in GENSHIN_CHARACTERS) {
            if (GENSHIN_CHARACTERS.hasOwnProperty(k)) tagOptions.push(k);
          }

          new android.app.AlertDialog.Builder(ctx)
            .setTitle("选择角色标签池")
            .setItems(tagOptions, function (dialog, which) {
              var tag = tagOptions[which];
              var info = GENSHIN_CHARACTERS[tag];

              showVoiceDialog("选择角色固定发音人", function (voice) {
                characterRecords.unshift({
                  name: name,
                  aliases: alias,
                  voice: voice,
                  usageCount: 100,
                  gender: info.gender,
