    function deleteBooksDialog() {
      var books = getBookList();
      if (books.length === 0) {
        toast("书籍列表为空");
        return;
      }

      var checked = [];
      for (var i = 0; i < books.length; i++) checked.push(false);

      new android.app.AlertDialog.Builder(ctx)
        .setTitle("选择要删除的书籍")
        .setMultiChoiceItems(books, checked, function (dialog, which, isChecked) {
          checked[which] = isChecked;
        })
        .setPositiveButton("删除选中", function () {
          var del = [];
          for (var i = 0; i < books.length; i++) {
            if (checked[i]) del.push(books[i]);
          }

          if (del.length === 0) {
            toast("未选择任何书籍");
            return;
          }

          var keep = [];
          for (var j = 0; j < books.length; j++) {
            if (del.indexOf(books[j]) === -1) keep.push(books[j]);
          }
          if (keep.length === 0) keep = ["默认"];

          writeJsonArray("liebiao.json", keep);

          for (var d = 0; d < del.length; d++) {
            try { ttsrv.deleteFile("shuming." + del[d] + ".json"); } catch (e) {}
          }

          var current = getCurrentBookName();
          if (del.indexOf(current) !== -1) useBook("默认");
          initBookSpinner();
          toast("已删除 " + del.length + " 个书籍");
        })
        .setNegativeButton("取消", function (dialog) { dialog.dismiss(); })
        .show();
    }

