    function searchRolesDialog() {
      showInputDialog("输入关键词，多个用 @ 分隔", function (text) {
        var raw = String(text || "").trim();
        if (!raw) {
          toast("搜索关键词不能为空");
          return;
        }

        var words = raw.split("@");
        var keywords = [];
        for (var i = 0; i < words.length; i++) {
          var w = normalizeString(words[i]);
          if (w) keywords.push(w);
        }

        var matched = [];
        var displayTexts = [];
        var indexMap = {};

        for (var j = 0; j < characterRecords.length; j++) {
          var ch = characterRecords[j];
          var name = normalizeString(ch.name || "");
          var aliases = normalizeString(ch.aliases || "");
          var hit = false;

          for (var k = 0; k < keywords.length; k++) {
            if (name.indexOf(keywords[k]) !== -1 || aliases.indexOf(keywords[k]) !== -1) {
              hit = true;
              break;
            }
          }

          if (hit) {
            var display = generateDisplayText(ch);
            displayTexts.push(display);
            indexMap[display] = j;
            matched.push(ch);
          }
        }

        if (displayTexts.length === 0) {
          toast("未找到匹配角色");
          return;
        }

        var checked = [];
        for (var c = 0; c < displayTexts.length; c++) checked.push(false);
        var order = [];

        new android.app.AlertDialog.Builder(ctx)
          .setTitle("选择角色（共 " + displayTexts.length + " 个）")
          .setMultiChoiceItems(displayTexts, checked, function (dialog, which, isChecked) {
            checked[which] = isChecked;
            if (isChecked) {
              if (order.indexOf(which) === -1) order.push(which);
            } else {
              var newOrder = [];
              for (var x = 0; x < order.length; x++) if (order[x] !== which) newOrder.push(order[x]);
              order = newOrder;
            }
          })
          .setPositiveButton("批量置顶", function () {
            var selectedNames = {};
            var selected = [];
            for (var o = 0; o < order.length; o++) {
              var idx = indexMap[displayTexts[order[o]]];
              var ch = characterRecords[idx];
              if (ch) {
                selected.push(ch);
                selectedNames[normalizeString(ch.name)] = true;
              }
            }

            if (selected.length === 0) {
              toast("没有选择角色");
              return;
            }

            var rest = [];
            for (var r = 0; r < characterRecords.length; r++) {
              if (!selectedNames[normalizeString(characterRecords[r].name)]) rest.push(characterRecords[r]);
            }

            characterRecords = selected.concat(rest);
            saveCharacterData();
            refreshCharacterList();
            toast("已置顶 " + selected.length + " 个角色");
          })
          .setNegativeButton("取消", function (dialog) { dialog.dismiss(); })
          .show();
      });
    }

    function diagnoseRoleFiles() {
      try {
        var currentBook = "";
        try { currentBook = normalizeBookName(getCurrentBookName()); } catch (e0) {}
        if (!currentBook) currentBook = "默认";

        function readRaw(name) {
          try {
            var v = readText(name, "");
            return String(v || "");
          } catch (e) {
            return "__READ_ERROR__ " + e.toString();
          }
        }

        function parseCount(raw) {
          try {
            var arr = JSON.parse(String(raw || "[]"));
            return Array.isArray(arr) ? arr.length : -2;
          } catch (e) {
            return -1;
          }
        }

        function shortText(raw) {
          raw = String(raw || "");
          raw = raw.replace(/\r/g, "\\r").replace(/\n/g, "\\n");
          if (raw.length > 360) raw = raw.substring(0, 360) + "...";
          return raw;
        }

        var bookFile = "shuming." + currentBook + ".json";
        var listRaw = readRaw("liebiao.json");
        var currentRaw = readRaw("characterRecords.json");
        var bookRaw = readRaw(bookFile);
        var gengxinRaw = readRaw("gengxin.json");
        var cunfangRaw = readRaw("cunfang.txt");

        var report = "";
        report += "【角色管理数据诊断】\n";
        report += "当前书名 getCurrentBookName(): " + currentBook + "\n";
        report += "cunfang.txt: " + shortText(cunfangRaw) + "\n\n";

        report += "liebiao.json 长度: " + listRaw.length + "\n";
        report += "liebiao.json 预览: " + shortText(listRaw) + "\n\n";

        report += "characterRecords.json 长度: " + currentRaw.length + "\n";
        report += "characterRecords.json 角色数: " + parseCount(currentRaw) + "\n";
        report += "characterRecords.json 预览: " + shortText(currentRaw) + "\n\n";

        report += bookFile + " 长度: " + bookRaw.length + "\n";
        report += bookFile + " 角色数: " + parseCount(bookRaw) + "\n";
        report += bookFile + " 预览: " + shortText(bookRaw) + "\n\n";

        report += "gengxin.json 长度: " + gengxinRaw.length + "\n";
        report += "gengxin.json 角色数: " + parseCount(gengxinRaw) + "\n";
        report += "gengxin.json 预览: " + shortText(gengxinRaw) + "\n\n";

        if (parseCount(bookRaw) <= 0 && parseCount(currentRaw) > 0) {
          report += "判断：当前书文件为空/没角色，但 characterRecords.json 有角色。可以点「强制继承」。\n";
        } else if (parseCount(bookRaw) > 0) {
          report += "判断：当前书文件本身有角色。如果界面不显示，是刷新/加载问题。\n";
        } else if (parseCount(currentRaw) <= 0) {
          report += "判断：当前全局角色文件也为空，说明不是没读到，而是当前可用角色数据为空。\n";
        }

        try {
          var clipboard = ctx.getSystemService(android.content.Context.CLIPBOARD_SERVICE);
          var clip = android.content.ClipData.newPlainText("角色管理数据诊断", report);
          clipboard.setPrimaryClip(clip);
        } catch (eClip) {}

        var builder = new android.app.AlertDialog.Builder(ctx);
        builder.setTitle("数据诊断：已复制到剪贴板");
        builder.setMessage(report);
        builder.setPositiveButton("确定", function(dialog) { dialog.dismiss(); });
        builder.show();
      } catch (e) {
        toast("诊断失败：" + e.toString());
      }
    }

